use gnosis_polyglot::cfg::{CfgNodeKind, ControlFlowGraph};
use gnosis_polyglot::source_map::SourceSpan;
use std::collections::BTreeMap;
use tree_sitter::Node;

pub struct GgCompiler {
    pub cfg: ControlFlowGraph,
    file_path: String,
    /// Exit node of the most recently compiled subgraph. For a single command
    /// this equals its entry; for a `list` (e.g. `A && B`) it's the LAST
    /// command, so a parent can chain the next command off the real tail rather
    /// than the head (which broke chains of 3+ like `A && B && C`).
    cur_exit: usize,
}

impl GgCompiler {
    pub fn new(file_path: &str) -> Self {
        Self {
            cfg: ControlFlowGraph::new(
                "main".to_string(),
                "bash".to_string(),
                file_path.to_string(),
            ),
            file_path: file_path.to_string(),
            cur_exit: 0,
        }
    }

    pub fn compile(&mut self, node: Node, source: &str) -> usize {
        let span = SourceSpan::from_tree_sitter(&self.file_path, &node);

        match node.kind() {
            "program" => {
                let entry_id = self.cfg.add_node(
                    CfgNodeKind::Entry {
                        name: "main".to_string(),
                    },
                    span.clone(),
                    "main".to_string(),
                );
                self.cfg.entry = entry_id;
                let mut last_id = entry_id;

                for i in 0..node.child_count() {
                    let child = node.child(i).unwrap();
                    let kind = child.kind();
                    if child.is_extra() || kind == ";" || kind == "\n" {
                        continue;
                    }

                    let child_id = self.compile_node(child, source);
                    self.cfg.add_edge(last_id, child_id, None);
                    last_id = child_id;
                }
                last_id
            }
            _ => self.compile_node(node, source),
        }
    }

    fn compile_node(&mut self, node: Node, source: &str) -> usize {
        let span = SourceSpan::from_tree_sitter(&self.file_path, &node);
        let label = node.utf8_text(source.as_bytes()).unwrap_or("").to_string();

        // Sentinel: arms whose exit != entry (the `list` arm) set cur_exit
        // explicitly; otherwise the fallback below sets exit = entry.
        self.cur_exit = usize::MAX;
        let entry = match node.kind() {
            // Bare `NAME=value` (no command). tree-sitter parses this as a
            // variable_assignment; the catch-all used to compile only its first
            // child (the name) and try to SPAWN it. Emit a Statement carrying the
            // full `NAME=value` text so the backend can set the env var.
            "variable_assignment" => {
                let mut props = BTreeMap::new();
                props.insert("source".to_string(), label.clone());
                self.cfg
                    .add_node_with_props(CfgNodeKind::Statement, span, label, props)
            }
            // `export FOO=bar` (also declare/local/readonly/typeset) parses as a
            // declaration_command whose first child is the bare keyword; the
            // catch-all used to recurse into that child and drop the assignment,
            // so `export FOO=bar` set nothing. Keep the full text as the source.
            "declaration_command" => {
                let mut props = BTreeMap::new();
                props.insert("source".to_string(), label.clone());
                self.cfg
                    .add_node_with_props(CfgNodeKind::Statement, span, label, props)
            }
            "command" => {
                let mut props = BTreeMap::new();
                props.insert("source".to_string(), label.clone());
                self.cfg
                    .add_node_with_props(CfgNodeKind::Statement, span, label, props)
            }
            "redirected_statement" => {
                let body = node.child_by_field_name("body").unwrap();
                let mut props = BTreeMap::new();
                props.insert(
                    "source".to_string(),
                    body.utf8_text(source.as_bytes()).unwrap_or("").to_string(),
                );

                for i in 0..node.child_count() {
                    let child = node.child(i).unwrap();
                    if child.kind() == "file_redirect" {
                        let dest = child.child_by_field_name("destination").unwrap();
                        let dest_str = dest.utf8_text(source.as_bytes()).unwrap_or("").to_string();
                        // Distinguish the file descriptor: `2>` redirects stderr,
                        // `>` / `1>` redirect stdout. Treating a `2>` as a stdout
                        // redirect (the previous behavior) silently dropped the
                        // command's stdout for the very common `cmd 2>/dev/null`.
                        let fd = child
                            .child_by_field_name("descriptor")
                            .and_then(|d| d.utf8_text(source.as_bytes()).ok())
                            .unwrap_or("");
                        // `>>` appends; `>` truncates. The whole redirect text
                        // carries the operator (`>>` vs `>`). Treating `>>` as `>`
                        // (the previous behavior) TRUNCATED the file — `echo x >>
                        // log` wiped the log instead of appending.
                        let append = child
                            .utf8_text(source.as_bytes())
                            .unwrap_or("")
                            .contains(">>");
                        if fd == "2" {
                            props.insert("stderr_to".to_string(), dest_str);
                            if append {
                                props.insert("stderr_append".to_string(), "1".to_string());
                            }
                        } else {
                            props.insert("stdout_to".to_string(), dest_str);
                            if append {
                                props.insert("stdout_append".to_string(), "1".to_string());
                            }
                        }
                    }
                }

                self.cfg
                    .add_node_with_props(CfgNodeKind::Statement, span, label, props)
            }
            "compound_statement" | "subshell" => self.compile_block(node, source, span),
            "pipeline" => {
                let mut props = BTreeMap::new();
                props.insert("mode".to_string(), "pipe".to_string());
                let pipe_id =
                    self.cfg
                        .add_node_with_props(CfgNodeKind::ConcurrentSpawn, span, label, props);

                for i in 0..node.child_count() {
                    let child = node.child(i).unwrap();
                    if child.kind() == "|" || child.is_extra() {
                        continue;
                    }
                    let id = self.compile_node(child, source);
                    self.cfg.add_edge(pipe_id, id, Some("pipe".to_string()));
                }
                pipe_id
            }
            "list" => {
                let mut first_id = None;
                let mut last_id = 0;

                let mut is_background = false;
                for i in 0..node.child_count() {
                    if node.child(i).unwrap().kind() == "&" {
                        is_background = true;
                        break;
                    }
                }

                if is_background {
                    let fork_id = self.cfg.add_node(
                        CfgNodeKind::ConcurrentSpawn,
                        span.clone(),
                        "FORK".to_string(),
                    );
                    first_id = Some(fork_id);
                    for i in 0..node.child_count() {
                        let child = node.child(i).unwrap();
                        let kind = child.kind();
                        if kind == "&" || kind == ";" || kind == "\n" || child.is_extra() {
                            continue;
                        }
                        let id = self.compile_node(child, source);
                        self.cfg.add_edge(fork_id, id, Some("fork".to_string()));
                    }
                } else {
                    // `&&` / `||` operators set the *condition* for the edge to
                    // the next command; `;` / newline are unconditional. The
                    // operator tokens themselves are not commands — skip them
                    // (compiling `&&` as a command is what previously ran it as a
                    // bogus program and broke the whole chain).
                    let mut pending_label: Option<String> = None;
                    let mut prev_exit = 0usize;
                    for i in 0..node.child_count() {
                        let child = node.child(i).unwrap();
                        let kind = child.kind();
                        if kind == "&&" {
                            pending_label = Some("on_success".to_string());
                            continue;
                        }
                        if kind == "||" {
                            pending_label = Some("on_failure".to_string());
                            continue;
                        }
                        if kind == ";" || kind == "\n" || child.is_extra() {
                            pending_label = None;
                            continue;
                        }
                        let id = self.compile_node(child, source);
                        // The child may be a subgraph (a nested `A && B`); chain
                        // the next command off its EXIT, not its head, so 3+-long
                        // chains (`A && B && C`) connect correctly.
                        let child_exit = self.cur_exit;
                        if first_id.is_none() {
                            first_id = Some(id);
                        } else {
                            self.cfg.add_edge(prev_exit, id, pending_label.take());
                        }
                        prev_exit = child_exit;
                        last_id = child_exit;
                    }
                }
                let entry = first_id.unwrap_or_else(|| {
                    let mut props = BTreeMap::new();
                    props.insert("source".to_string(), label.clone());
                    self.cfg
                        .add_node_with_props(CfgNodeKind::Statement, span, label, props)
                });
                // This list's exit is its last command's exit (or the fork /
                // fallback node). Lets a parent chain off the real tail.
                self.cur_exit = if last_id != 0 { last_id } else { entry };
                entry
            }
            _ => {
                if node.child_count() > 0 {
                    self.compile_node(node.child(0).unwrap(), source)
                } else {
                    let mut props = BTreeMap::new();
                    props.insert("source".to_string(), label.clone());
                    self.cfg
                        .add_node_with_props(CfgNodeKind::Statement, span, label, props)
                }
            }
        };
        // Arms that didn't set a distinct subgraph tail exit at their entry.
        if self.cur_exit == usize::MAX {
            self.cur_exit = entry;
        }
        entry
    }

    fn compile_block(&mut self, node: Node, source: &str, span: SourceSpan) -> usize {
        let mut children = Vec::new();

        let mut list_node = None;
        for i in 0..node.child_count() {
            let child = node.child(i).unwrap();
            if child.kind() == "list" {
                list_node = Some(child);
                break;
            }
        }

        if let Some(l_node) = list_node {
            for i in 0..l_node.child_count() {
                let child = l_node.child(i).unwrap();
                let kind = child.kind();
                if kind == ";" || kind == "\n" || child.is_extra() {
                    continue;
                }
                children.push(child);
            }
        } else {
            for i in 0..node.child_count() {
                let child = node.child(i).unwrap();
                let kind = child.kind();
                if kind == "{"
                    || kind == "}"
                    || kind == "("
                    || kind == ")"
                    || kind == ";"
                    || kind == "\n"
                    || child.is_extra()
                {
                    continue;
                }
                children.push(child);
            }
        }

        if children.is_empty() {
            let mut props = BTreeMap::new();
            props.insert("source".to_string(), "".to_string());
            return self.cfg.add_node_with_props(
                CfgNodeKind::Statement,
                span,
                "empty_block".to_string(),
                props,
            );
        }

        let first_text = children[0]
            .utf8_text(source.as_bytes())
            .unwrap_or("")
            .trim();
        if first_text == "race" {
            let mut props = BTreeMap::new();
            props.insert("mode".to_string(), "race".to_string());
            let race_id = self.cfg.add_node_with_props(
                CfgNodeKind::ConcurrentSpawn,
                span,
                "RACE".to_string(),
                props,
            );
            for child in &children[1..] {
                let id = self.compile_node(*child, source);
                self.cfg.add_edge(race_id, id, Some("race".to_string()));
            }
            race_id
        } else {
            let mut first_id = None;
            let mut last_id = 0;
            for child in children {
                let id = self.compile_node(child, source);
                if first_id.is_none() {
                    first_id = Some(id);
                } else {
                    self.cfg.add_edge(last_id, id, None);
                }
                last_id = id;
            }
            first_id.unwrap()
        }
    }
}
